dd, mm, yyyy = list(map(int, input("Enter date (dd mm yyyy): ").split()))
print(f"The day of the week on {dd}/{mm}/{yyyy} is: {["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"][((yyyy-1)%400 + ((yyyy-1)%400)//4 + sum([3, 0 if (yyyy%4 == 0 and yyyy%100!= 0) else 1, 3, 2, 3, 2, 3, 3, 2, 3, 2, 3][:mm-1]) + dd)%7]}")